/* lab-decant: zero-radius, border-only, monospace data-grid tuning */

/* --- global resets --- */
*,
*::before,
*::after {
  border-radius: 0 !important;
  box-shadow: none !important;
}

/* --- page / surface hierarchy --- */
body {
  background-color: var(--wp--preset--color--base);
  font-family: var(--wp--preset--font-family--sans);
  font-weight: 400;
}

/* --- section vertical rhythm --- */
.wp-site-blocks > * + * {
  margin-block-start: var(--wp--preset--spacing--xl);
}
.wp-site-blocks section,
.wp-site-blocks .wp-block-group {
  padding-block: var(--wp--preset--spacing--lg);
}

/* --- card chrome: surface fill + heavy border, no shadow --- */
.wc-block-grid__product,
.wc-block-components-product-card,
ul.products li.product,
.wp-block-woocommerce-product-new .wc-block-grid__product,
.wo-card,
.wp-block-post {
  background-color: var(--wp--preset--color--surface);
  border: 1.5px solid var(--wp--preset--color--border);
  padding: var(--wp--preset--spacing--sm);
  box-shadow: none !important;
}

/* --- section dividers --- */
.wp-block-separator,
.wc-block-components-totals-item {
  border-color: var(--wp--preset--color--border);
  border-width: 1.5px;
}

/* --- section headings: tertiary, reduced size --- */
h2, h3, .wp-block-heading {
  color: var(--wp--preset--color--tertiary);
  font-size: var(--wp--preset--font-size--md, 1rem);
  font-weight: 500;
  font-family: var(--wp--preset--font-family--sans);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

/* --- hero headline: monospace display --- */
.wp-block-site-title,
.wp-block-site-tagline,
.hero-headline,
.wp-block-heading.is-style-display {
  font-family: var(--wp--preset--font-family--display);
  font-weight: 700;
  color: var(--wp--preset--color--contrast);
}

/* --- price, mL qty, lot/batch: monospace + contrast --- */
.wc-block-components-product-price,
.price,
bdi,
.wo-lot,
.wo-batch,
.wo-ml {
  font-family: var(--wp--preset--font-family--mono);
  font-weight: 600;
  color: var(--wp--preset--color--contrast);
}

/* --- secondary metadata: muted --- */
.wc-block-components-product-meta,
.product_meta,
.wo-meta-label,
.wo-house-label {
  font-family: var(--wp--preset--font-family--mono);
  font-weight: 400;
  color: var(--wp--preset--color--muted);
  font-size: 0.75rem;
  letter-spacing: 0.04em;
}

/* --- buttons: rectangular, accent fill, no radius --- */
.wp-block-button__link,
.wc-block-components-button,
.button,
button,
input[type="submit"] {
  border-radius: 0 !important;
  background-color: var(--wp--preset--color--accent);
  color: var(--wp--preset--color--base);
  font-family: var(--wp--preset--font-family--sans);
  font-weight: 500;
  font-size: 0.8125rem;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  border: 1.5px solid var(--wp--preset--color--accent);
  padding: var(--wp--preset--spacing--xs) var(--wp--preset--spacing--md);
  box-shadow: none !important;
  transition: background-color 0.15s ease, color 0.15s ease;
}
.wp-block-button__link:hover,
.wc-block-components-button:hover,
.button:hover,
button:hover,
input[type="submit"]:hover {
  background-color: var(--wp--preset--color--primary-hover);
  border-color: var(--wp--preset--color--primary-hover);
  color: var(--wp--preset--color--base);
}

/* --- category strip tiles: border-only, accent-soft hover, mono label --- */
.wp-block-navigation-item__content,
.wo-category-tile,
.wp-block-term-description {
  border: 1.5px solid var(--wp--preset--color--border);
  padding: var(--wp--preset--spacing--xs) var(--wp--preset--spacing--sm);
  font-family: var(--wp--preset--font-family--mono);
  font-weight: 400;
  font-size: 0.75rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  background-color: transparent;
  transition: background-color 0.15s ease;
}
.wo-category-tile:hover,
.wp-block-navigation-item:hover .wp-block-navigation-item__content {
  background-color: var(--wp--preset--color--accent-soft);
}

/* --- product grid: 4-col desktop, 2-col tablet, 1-col mobile --- */
.wc-block-grid__products,
ul.products {
  display: grid !important;
  grid-template-columns: repeat(4, minmax(0, 1fr)) !important;
  gap: var(--wp--preset--spacing--sm) !important;
}
@media (max-width: 1024px) {
  .wc-block-grid__products,
  ul.products {
    grid-template-columns: repeat(2, minmax(0, 1fr)) !important;
  }
}
@media (max-width: 600px) {
  .wc-block-grid__products,
  ul.products {
    grid-template-columns: minmax(0, 1fr) !important;
  }
}

/* --- form inputs: rectangular, heavy border --- */
input[type="text"],
input[type="email"],
input[type="search"],
input[type="number"],
select,
textarea {
  border-radius: 0 !important;
  border: 1.5px solid var(--wp--preset--color--border);
  font-family: var(--wp--preset--font-family--sans);
  background-color: var(--wp--preset--color--base);
  padding: var(--wp--preset--spacing--xs) var(--wp--preset--spacing--sm);
}
input[type="text"]:focus,
input[type="email"]:focus,
input[type="search"]:focus,
select:focus,
textarea:focus {
  border-color: var(--wp--preset--color--accent);
  outline: none;
  box-shadow: none !important;
}

/* --- sale / stock badges: mono, rectangular --- */
.onsale,
.wc-block-components-product-sale-badge {
  border-radius: 0 !important;
  font-family: var(--wp--preset--font-family--mono);
  font-size: 0.6875rem;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  background-color: var(--wp--preset--color--accent);
  color: var(--wp--preset--color--base);
  padding: 0.125rem 0.375rem;
}

/* --- star ratings: accent colour --- */
.star-rating span::before,
.wc-block-components-review-list-item__rating .wc-block-components-product-rating__stars::before {
  color: var(--wp--preset--color--accent);
}

/* --- max-width cap on sections --- */
.wp-site-blocks > .alignfull {
  max-width: 100%;
}
.wp-site-blocks > *:not(.alignfull):not(.alignwide) {
  max-width: var(--wp--style--global--content-size, 1200px);
  margin-inline: auto;
}

/* --- suppress excessive whitespace in editorial sections --- */
.wp-block-spacer {
  max-height: 3rem !important;
}
